DECLARE 
  QTDE NUMBER := 0;
BEGIN

   SELECT COUNT(*)
   INTO QTDE
   FROM TGQPRIORIDADE;

    IF (QTDE = 0) THEN 

 	INSERT INTO TGQPRIORIDADE (IDPRIORIDADE,DESCRICAO)
	(SELECT 1, 'Simples' FROM dual
	UNION ALL
	SELECT 2, 'Prioritario' FROM dual
	UNION ALL
	SELECT 3, 'Critico' FROM dual);

	COMMIT;
  END IF;
END
;/

/*
NomeObjeto: INSERTTGQFASESGM
