	INSERT INTO TGQFASESGM (FASESID,DESCFASE) VALUES ( 3,'Acoes da Gestao de Mudanca');

	INSERT INTO TGQFASESGM (FASESID,DESCFASE) VALUES ( 4,'Avaliacao de Riscos das Acoes');

	INSERT INTO TGQFASESGM (FASESID,DESCFASE) VALUES ( 5,'Avaliacao da Proposta de Mudanca');

	COMMIT;
  END IF;
END;

