sql.mssql:


CREATE OR REPLACE TRIGGER TRG_INS_UPD_TGQACOESCORRETIVAS ON TGQACOESCORRETIVAS
INSTEAD OF INSERT OR UPDATE  AS
BEGIN
  DECLARE @DATAACAO DATE,
                   @CODUSU INT

  SET @DATAACAO = GETDATE();
  SET @CODUSU = STP_GET_CODUSULOGADO;

 UPDATE TGQACOESCORRETIVAS
  SET DATAACAO = @DATAACAO,
         CODUSU = @CODUSU
WHERE IDACOES = (SELECT IDACOES FROM INSERTED)

END;

