CREATE OR REPLACE TRIGGER TRG_UPD_TGQRESPGESTAOMUDANCA
BEFORE UPDATE ON TGQRESPGESTAOMUDANCA FOR EACH ROW
BEGIN

	IF (:OLD.CODUSU = STP_GET_CODUSULOGADO AND :NEW.CODUSU = STP_GET_CODUSULOGADO) THEN 
		IF (:NEW.APROVADO = 'S' AND :NEW.REPROVADO = 'S') THEN 
	       STP_MSGERRO('Nao é permitido marcar Aprovado e Reprovado ao mesmo tempo.', null, NULL);
	    END IF;

	    IF (:NEW.APROVADO = 'N' AND :NEW.REPROVADO = 'S' AND :NEW.OBSNAOAPROVADO IS NULL) THEN 
	       STP_MSGERRO('No caso de reprovado, favor preencher o motivo da reprova.', null, NULL);
	    END IF;

	   	 :NEW.DATAAPROVACAO := SYSDATE;
	   	 SELECT NOMEUSU
	   	 INTO :NEW.ASSINATURA
	   	 FROM TSIUSU 
	   	 WHERE CODUSU = STP_GET_CODUSULOGADO;
   	ELSE 
   	   :NEW.DATAAPROVACAO := null;
   	   :NEW.ASSINATURA := null;
   	   STP_MSGERRO('Assinatura nao corresponde ao usuario selecionado.', null, NULL);
   	END IF;
END;



