CREATE OR REPLACE TRIGGER TRG_INC_TGFCAB_QUALIF
BEFORE INSERT ON TGFCAB FOR EACH ROW
DECLARE
       P_QUALIFIC		  CHAR;
       P_VALIDADE		  DATE;
       P_DATADIA 		  DATE;	
       P_COUNT			  NUMBER(10) := 0;
       P_CONFIG           CHAR;
       ERRMSG             VARCHAR2(500);

BEGIN   
	IF (:NEW.TIPMOV = 'C') OR (:NEW.TIPMOV = 'O') THEN

	   SELECT NVL(CONTROLEFORNECEDOR,'N')
	   INTO P_CONFIG
       FROM TGQCONFIG CFG
       WHERE CODEMP = :NEW.CODEMP ;

	   IF (P_CONFIG = 'S') THEN

		BEGIN
	      SELECT Q.QUALIFICACAO, MAX(TO_CHAR(Q.DATAVALIDADE,'DD/MM/YYYY')) DATAVALIDADE, TO_CHAR(SYSDATE,'DD/MM/YYYY') DATADIA
	      INTO P_QUALIFIC, P_VALIDADE, P_DATADIA 
		  FROM TGQQUALIFFORN Q
		  WHERE Q.CODPARC = :NEW.CODPARC
		  AND TO_CHAR(Q.DATAVALIDADE,'DD/MM/YYYY') =  (SELECT MAX(TO_CHAR(QF.DATAVALIDADE,'DD/MM/YYYY')) FROM TGQQUALIFFORN QF WHERE QF.CODPARC = Q.CODPARC)
		  GROUP BY Q.QUALIFICACAO,  TO_CHAR(SYSDATE,'DD/MM/YYYY');
		EXCEPTION WHEN no_data_found THEN 
 			RAISE_APPLICATION_ERROR(-20101,'Fornecedor nao possui qualificacao não podera ser feita a geracao do Pedido / Nota. Favor verificar. ');
		END;  

		 IF (P_QUALIFIC = 'E') THEN 
		 	 RAISE_APPLICATION_ERROR(-20101,'Fornecedor em Processo de Qualificacao, nao podera ser feita a geracao do Pedido / Nota. Favor verificar.');
		 END IF;

		 IF (P_QUALIFIC = 'D') THEN 
		 	 RAISE_APPLICATION_ERROR(-20101,'Fornecedor Desqualificado, nao podera ser feita a geracao do Pedido / Nota. Favor verificar.');
		 END IF;

		 IF (P_VALIDADE <= P_DATADIA) THEN 
		 	 RAISE_APPLICATION_ERROR(-20101,'Fornecedor com qualificacao vencida, nao podera ser feita a geracao do Pedido / Nota. Favor verificar.');
		 END IF;
      END IF;
    END IF;
END;



CREATE OR REPLACE TRIGGER TRG_INS_UPD_TGQRNC
BEFORE INSERT OR UPDATE ON TGQRNC FOR EACH ROW
BEGIN

 IF (inserting) THEN 

 	:NEW.FASESNCID := 1;
    :NEW.DATAREGISTRO := SYSDATE;

    SELECT :NEW.DATAREGISTRO + O.PRAZODIAS
    INTO :NEW.DATAPREVENCERRAR 
    FROM TGQCADASTROS O
    WHERE O.ID = :NEW.ORIGEM;

 END IF;

 IF (:OLD.FASESNCID <> :NEW.FASESNCID) THEN 

     INSERT INTO TGQREGFASES (RNCID, IDREGFASES, FASESNCID, DATAFASE, CODUSU)
	 VALUES (:NEW.RNCID, SEQ_TGQREGFASES.NEXTVAL, :NEW.FASESNCID, SYSDATE,STP_GET_CODUSULOGADO);

 END IF;

END;



CREATE OR REPLACE TRIGGER TGR_INS_UPD_PRAZO
BEFORE INSERT OR UPDATE ON TGQCADASTROS FOR EACH ROW
BEGIN

 RETURN;

 IF (:NEW.TIPOCADASTRO = 1 AND :NEW.PRAZODIAS = NULL) THEN 

  RAISE_APPLICATION_ERROR(-20101, 'Informar o Prazo em dias para o tipo de cadastro Origem RNC.');

 END IF;
END;



